var webApp=function(dnaDom,fetchJson,prettyPrintJson){"use strict";const appConfig={apiServers:[{website:"localhost",api:"http://localhost:2121/api/v1/"}]};const utils={isCurrentWebsite(server){return server.website===globalThis.location.hostname}};const appLookup={apiServer:appConfig.apiServers.find(utils.isCurrentWebsite)?.api};const appUi={logApiCall(method,path){const citeElem=globalThis.document.querySelector("main cite");citeElem.querySelector("code").textContent=method;citeElem.querySelector("output").textContent=appLookup.apiServer+path},handleBooks(data){const outputElem=globalThis.document.querySelector("main >pre >output");outputElem.innerHTML=prettyPrintJson.prettyPrintJson.toHtml(data);dna.ui.fadeIn(outputElem,{duration:1e3,reset:true});return outputElem}};const appAction={getBooks(){const path="books";appUi.logApiCall("GET",path);fetchJson.fetchJson.get(appLookup.apiServer+path).then(appUi.handleBooks)},getBook(button){const id=button.dataset.book;const path="books/"+id;appUi.logApiCall("GET",path);fetchJson.fetchJson.get(appLookup.apiServer+path).then(appUi.handleBooks)},deleteBook(button){const id=button.dataset.book;const path="books/"+id;appUi.logApiCall("DELETE",path);fetchJson.fetchJson.delete(appLookup.apiServer+path).then(appUi.handleBooks)},bogus(){const path="bogus";appUi.logApiCall("GET",path);fetchJson.fetchJson.get(appLookup.apiServer+path).then(appUi.handleBooks)}};const webApp={action:appAction,setup(){fetchJson.fetchJson.enableLogger();console.info("simple-node-mvc-starter-project",appLookup.apiServer)}};dnaDom.dna.dom.onReady(webApp.setup);return webApp}(globalThis,globalThis,globalThis);
